import javax.inject._
import play.api.mvc._
import scala.concurrent.{ExecutionContext, Future}
import slick.jdbc.PostgresProfile.api._

@Singleton
class ProductController @Inject()(dbConfigProvider: DatabaseConfigProvider,
                                 cc: ControllerComponents)(implicit ec: ExecutionContext)
  extends AbstractController(cc) {

  val dbConfig = dbConfigProvider.get[JdbcProfile]

  def searchProducts(query: Option[String]): Action[AnyContent] =
    Action.async { implicit request =>
      val searchTerm = query.map(_.toLowerCase).getOrElse("%")
      val sqlFragment = if (searchTerm != "%") s"name LIKE '$searchTerm%'" else "1=1"
